import React from 'react';
import LoginForm from './components/imports/LoginForm.jsx';
import RegistrationForm from './components/imports/RegistrationForm.jsx';
import BaseLogin from './components/imports/BaseLogin.jsx';

export default function Login() {
  return (
    <div id="login">
    <div className="container">
      <div className="row login-box">
         <BaseLogin/>
         <LoginForm/>

      </div>
    </div>
  </div>
  )
}
